import UIKit

class NedirVC: UIViewController {

    @IBOutlet weak var tableView: UITableView!
    
    var bilgiler = [Bilgilendirme]()
    var bilgiSec : Bilgilendirme?
    
    override func viewDidLoad() {
        super.viewDidLoad()
        
        tableView.delegate = self
        tableView.dataSource = self
        
        bilgiEkle()
    }
    func bilgiEkle(){
        let bilgi1 = Bilgilendirme(Title: "Uykunun Beden ve Zihin Üzerindeki Etkileri?", Image: UIImage(named: "bilgi")!, Details: "Uyku, beyin plastisitesi teorisine göre nöronların yeniden düzenlenmesine yardımcı oluyor. Ayrıca gün içinde vücutta biriken toksinler, uyku boyunca çalışan glifatik sistem sayesinde merkezi sinir sisteminden temizleniyor. Yapılan araştırmalara göre gereksiz bilgileri silerek hafıza işlevine de katkı sağlıyor. Üstelik kısa süreli hatıralar, uzun süreli hatıralara uyku aracılığıyla dönüştürülüyor. Enerji koruma teorisine göre uyku, metabolizma hızını düşürerek enerji tasarrufu sağlıyor. Restoratif teoriye göreyse hücre onarımı ve yenilenmesine katkıda bulunuyor.Uykunun zihin üzerinde de farklı etkileri var. Uyurken beynin duyguları düzenleyen amigdala ve hipokampüs bölgelerinde aktivite artışı yaşanıyor. Bu artış, sağlıklı zihinsel fonksiyonları ve duygusal istikrarı koruyan etkiler yaratıyor. Buradan hareketle yapılan uyku araştırmaları, uyku ile zihin sağlığı arasındaki korelasyona odaklanıyor. Yapılan bir çalışmaya göre düşük uyku kalitesi ve yetersiz uyku, zihinsel sağlığı olumsuz etkileyerek duygu durum bozukluklarını tetikleyebiliyor. Ayrıca bir diğer çalışmanın sonuçlarına göre uyku bozuklukları ve depresyon arasında oldukça güçlü bir çift taraflı ilişki yaşanıyor.")
        bilgiler.append(bilgi1)
        let bilgi2 = Bilgilendirme(Title: "Meditasyon Beyni ve Vücudumuzu Nasıl Etkiler?", Image: UIImage(named: "bilgi2")!, Details: "İç Huzuru Artırır - Meditasyon, insanların iç huzurunu artırır. Meditasyon uygulaması kişilerin kendini tanıma, kendini dinleme ve zaman ayırma pratikleri içerir. Bu sayede kişi zihnindeki karmaşık düşüncelerden uzaklaşarak sakinleşir. Zihin boşalır ve öz farkındalık gelişir. İnsanlar meditasyon ile kendilerini dış dünyanın karmaşasından uzaklaştırır. Bu sayede tazelenir ve dinginleşir.Meditasyon Odaklanmayı Artırır - Meditasyonun zihni berraklaştırmak ve sakinleştirmektir. Meditasyon sayesinde insan bedeni ve zihni sakinleşir. Gün içerisinde meditasyon sayesinde daha iyi odaklanabilir. Bu sayede endişe ve stres seviyesi azalır. Meditasyonun odaklanmayı artırması günlük yaşamı olumlu yönde etkiler.Stres Seviyesini Düşürür - Meditasyon, günlük yaşamın düzenlenmesine katkı sağlar. Özellikle şehir yaşamında doğa ve toprağa ulaşamamak stres ve endişe yaratır. Meditasyon yaparak günlük yaşamın stres ve kaygılarından uzaklaşabilirsiniz. Meditasyon ile sadece iş yaşamında değil sosyal yaşamda da stres seviyeniz önemli ölçüde azalacaktır.Vücudunuzu Dinlendirir - Meditasyon yapan kişilerin zihinleri boşalır ve tazelenir. Yoğun yaşam koşuşturmasından ve stresinden uzaklaşarak meditasyon yapmak vücudun dinlenmesini sağlar. Meditasyonda anda kalmak önemlidir. Bu sayede vücudunuz anda kalarak dinlenmeye vakit bulur.Psikolojik Olarak Rahatlama Sağlar - Şehir yaşamının getirmiş olduğu yoğunluk insanları mutsuzluğa ve depresyona itebilir. İş ve ev odaklı bir yaşam, doğanın uzağında kalmak kişiyi stres ve gerginliğe doğru iter. Bu durumda kişi, mutsuz ve gergin bir yaşam sürer. Meditasyon, kişiyi günlük yaşamın stresinden uzaklaştırarak rahatlatır. Anda kalarak farkındalığı artırmayı amaçlayan meditasyon olaylar karşısında sakin ve dingin kalmayı sağlar. Bu durum, psikolojik rahatlama sağlar.Sevgi ve Şefkati Artırır - Günlük yaşam içerisinde kendimize ve çevremizdekilere yeterince sevgi ve şefkat göstermeyebiliriz. Sadece kendi problemlerimizi görür, bunlarla ilgilenmek isteyebiliriz. Meditasyon uygulaması ile birlikte yorgunluk ve stres seviyemiz azalır. Bu sayede etrafımızda olup bitenlere yoğunlaşma imkânı elde edebiliriz. Sevdiklerimize yakınlık gösterebiliriz. Yalnızca insanlara değil hayvanlara da daha şefkatli ve sevgi dolu yaklaşabiliriz.Yaratıcılık Seviyesi Artar - Meditasyon odaklanmayı artıran bir uygulamadır. Düzenli meditasyon yapan kişilerde odaklanma artar. Bu durumda kişi ve durumlara, çalışmalara daha fazla odaklanmak mümkündür. Yapacağınız bir işe, çalışmaya rahatlıkla odaklanmak mümkündür. Bu sayede özellikle yaratıcılık gerektiren işlerde daha kreatif çalışmalar elde edilebilir.")
        bilgiler.append(bilgi2)

        let bilgi3 = Bilgilendirme(Title: "Kalp Çakrası Nedir, Kalp Çakrasını Güçlendirmenin Yolları", Image: UIImage(named: "bilgi3")!, Details: "Dengesiz ruh hali, duygusal dermansızlık ve yabancılık hissi gibi durumlar yaşamanın en önemli nedenlerinden biri kalp çakrasının doğru çalışmamasından kaynaklanır. Dengeli bir duygu dünyası için gereken pozitif enerjinin sağlamasına yardımcı olan bu çakra, göğüste yer aldığından dolayı tüm çakraları birbirine bağlayan bir konumda bulunduğu için yaşamın tüm alanlarında önemlidir.Kalp çakrası, vücuttaki enerji akışını kontrol edebilmeye ve pozitif hareket edebilmeye yarayan kalp çakrası, aynı zamanda vücudun sevgi enerjisinden de sorumludur. Bu sebeple sevgisizlik, şefkate ihtiyaç duyma gibi hislerin varlığı; kalbe, akciğerlere, vücut kaslarına ve bağışıklık sistemine olumsuz yönde etkiler bırakır.Affetmek, sevmek, şefkat göstermek gibi duyguların açığa çıkmasına ve manevi olarak iyileşmeye yönelmeyi sağlayan kalp çakrası; nefret, bencillik, kıskançlık gibi negatif duyguları kişiden uzaklaştırır.Kalp çakrasının açık ve güçlü olması, sevginin paylaştıkça çoğalmasını sağlar. Kalp çakrasını açmaya ve dengelemeye yardımcı olan pek çok yol bulunur.Kalp çakrasını güçlendirmek için meditasyon, dua, çeşitli ritüeller yapılabilir. Renklerin ve doğanın gücünden faydalanmak, kalp çakrasına iyi gelen doğal taşlardan ve aromatik yağlardan yararlanmak da kalp çakrasının güçlenmesine yardımcı olur.Kişinin içerisinde bulunan sevgiyi uyandırmak ve kalp çakrasını güçlendirmek için çeşitli yöntemler aşağıdaki gibidir;Kalp çakrasını güçlendirme konusunda en etkili yöntem kişinin kendini sevmesidir. Kendini seven birey, içinden yayılan sevgiyi ailesine, arkadaşlarına, doğaya yönlendirebilir. İçinizdeki sevgiyi şifalandıracak olan olumlama cümleleri ile yaşamınıza sevgiyi ve şefkati çağırabilirsiniz. Mum, tütsü veya esansiyel yağlardan yararlanarak olumlamalarınızı destekleyebilirsiniz. Bunlarla birlikte çeşitli hoş kokular ile iyileşme niyeti ile kalp çakranızın açılmasına yardımcı olabilirsiniz.Çeşitli meditasyonlar ile güçlendirebileceğiniz kalp çakrası, sakin bir mekanda şifa enerjisinin akışında etkili olabilir. Kalp çakrası için özel meditasyonlar yapmak gerekir. Sessiz ve huzurlu bir ortamda günlük 10 dakikalık çalışmalarla kalp çakrasına şifa enerjisinin akışını sağlayabilirsiniz.Dengeli beslenmek ve stresli ortamlarda bulunmamayı tercih etmek de negatif enerjileri uzak tutarak duygusal açıdan sağlam olabilmenizi sağlar. Bu sayede olumsuz enerjileri sizden uzak tutarak şefkatli, mutlu ve huzurlu bir yaşam oluşturabilmeye olanak verir.Kalp çakrasını dengeleyecek ve olumsuz etkilerden koruyacak olan bir diğer unsur da sarılmaktır. Sevdiğiniz birine sarıldığınızda oluşan enerji, sarılma eyleminin sevgi alıp verme eylemine dönüşmesini sağlar. Sevmek ve paylaşmak hissini ortaya çıkaran bu enerji, kalp çakranızın açılmasına olumlu yönde katkılarda bulunur.Sizi olumsuz yönde etkileyen ve negatif enerji yaydığını düşündüğünüz insanlardan uzak durmak kalp çakrasının dengelenmesine yardımcı olacaktır.Kalp çakrasını güçlendirmek için aromatik gül yağının kokusundan faydalanılabilir. Aromatik gül yağının kokusu kalp çakrasına iyi gelmektedir. Kalp çakrasını güçlendirmek için gül yağı aromasıyla kalp çakranızı yükseltebilirsiniz.")
        bilgiler.append(bilgi3)

        let bilgi4 = Bilgilendirme(Title: "Mucizevi Bir Terapi Yöntemi: Müzik Dinlemek", Image: UIImage(named: "bilgi4")!, Details: "1. Yeni Nesil Sakinleştirici - Sevdiğiniz Şarkılar : Amerika’da bir üniversitenin yaptığı araştırmaya göre, yoğun bakım tedavisi gören hastaların favori şarkılarını dinlemeleri, kaygı eşiklerini üçte bir oranında düşürmüştür.2. Atmosferik Müzikler ve Form : Müziğin vücut sağlığında iyi olduğu konulardan bir diğeri de iştahı sakinleştirmesidir. Ünlü bir Amerikan restoran zinciri, restoranlarından birini daha yumuşak aydınlatma ve caz müzik gibi faktörlerle bir dönüşüm içerisine soktu. Daha sonra yapılan araştırma gösterdi ki bu dönüşüm sonrasında restorana gelen kişiler %18 daha az yemek tüketmesine karşın yemeklerinden çok daha fazla keyif aldıklarını belirtti.3. Enstrümantal Müzik ve Odaklanma : Northumbria Üniversitesi tarafından yapılan bir araştırma gösteriyor ki; Vivaldi’nin Dört Mevsim isimli meşhur eserini dinleyen kişilerin ruh hali ve konçertolar sayesinde zihinsel uyanıklık seviyeleri yükselmiş. Genç yetişkinler, iç açıcı Bahar konçertosu eşliğinde daha verimli ve odaklanmış bir şekilde çalışırken, görece daha yavaş bir ritme sahip olan Sonbahar konçertosunu dinleyen gruba nazaran daha iyi ve daha verimli çalışmış.4. Kan Damarları : 2013 yılında Hollandalı araştırmacılar tarafından yapılan bir araştırmaya göre, günde 30 dakika sevdikleri müzikleri dinleyen kalp hastalarının kan damarları genişlemiş ve iyileşmiştir. Egzersiz sırasında sevdikleri şarkıları dinleyen hastaların, dolaşım sistemlerinde daha fazla iyileşme görmüşlerdir. Müzik dinlemek, kandaki nitrik oksit gazının üretimini artırarak kan damarlarının genişlemesine yardımcı olur ve esneklik sağlar.5. Şarkı Söylemek ve Mutluluk : Bir grup İngiliz araştırmacı, koro halinde şarkı söyleyen, yalnız şarkı söyleyen ve bir takım sporu yapan 3 farklı grup ile toplam 375 kişi üzerinde araştırma yapmıştır. Her bir aktivite, duygusal olarak kişilerin daha iyi olmasında etkili olmuş fakat koro halinde şarkı söyleyen kişilerin, yalnız şarkı söyleyen kişilere oranla çok daha mutlu hissettikleri gözlemlenmiştir. Bunun yanı sıra, koro üyelerinin yaşadıkları sosyal tecrübe, takım sporu yapan kişilere göre daha etkili olduğu ortaya çıkmıştır.6. Enstrüman Çalmak ve Kıvrak Zekâ : Orta yaş ve üzeri bireyler başta olmak üzere, çocukken uzun süre boyunca enstrüman çalan insanların, beyinlerinin olay ve konuşmalara reaksiyon süreleri diğer insanlara nazaran oldukça yüksek çıkmıştır.7. Sakin Şarkılar ve Öfke Kontrolü : Stresle başa çıkmanın en etkili yollarından birisi müzik dinlemek… İstanbul gibi trafiğin ve şehir içi kaosun yüksek olduğu şehirlerde insanlar fazlası ile yıpranıyor. 2013’te yapılan bir araştırmaya göre, bu tarz durumlarda sakin ve yumuşak bir şarkı dinlemek daha sakin hissetmeye ve devamında da trafikte daha az hata yapmaya yardımcı olduğunu gösteriyor.")
        bilgiler.append(bilgi4)

        let bilgi5 = Bilgilendirme(Title: "Biyolojik Saati Ayarlama ve Günü Etkin Kullanma Yöntemleri", Image: UIImage(named: "bilgi5")!, Details: "Vücudumuz da tıpkı her gecenin bir gündüze uyanması gibi “doğal ritmine” göre işliyor. Beynimizin hipotalamus bölgesinde bulunan birtakım sinir hücresi bedenimize sinirsel ve hormon bazlı sinyaller göndererek yaşantımızı ve devamında yaşam ritmimizi düzenler. Yani, biyolojik saat otomatik olarak uyku, nabız, vücut sıcaklığı ve uyku gibi pek çok hayati fonksiyonumuzu düzenliyor.“Biyolojik Saatle Yaşamak” isimli eserin sahibi Dr. Jan Dirk Fauteck, “Biyolojik saatimize karşı gelecek şekilde yaşarsak mutsuz olur ve daha kısa sürede hastalanırız” diyor. Buna ilaveten, biyolojik saatine uyumlu yaşayanların iş verimini artırabileceğini, daha mutlu bir yaşam sürebileceğini ve güzelliklerini uzun yıllar koruyabileceğini söylüyor.07.00 – 09.00 : Beden: Bedenimiz sabahın erken saatlerinde ağrıya karşı pek bir duyarlı olabiliyor. Sabahın erken saatlerinde yaşanan diş ağrısı, öğleden sonra yaşanan bir ağrıya göre yaklaşık dört kat daha güçlü hissediliyor. Migren ağrılarının en sık sabah saatlerinde ortaya çıkması da bu sebepten... Romatizma gibi iltihabi bir rahatsızlığınız varsa, sabahları eklemlerinizi gereksiz hareketlerle zorlamamanızı tavsiye ederiz. Kalp rahatsızlığı olanlar da bu saatlerde ekstra dikkatli olmalılar çünkü bu saatlerde nabız daha hızlı attığı için kalp krizi ve felç geçirme riski de artıyor.Zihin: Güne zihnen tam anlamı ile başlamak için sabahları uzun bir süreye ihtiyaç duyuyorsanız, alarmınızı bir 15-20 dakika erkene alın. Yataktan çıkmakta güçlük çekiyorsanız, perdelerinizi açık bırakarak uyumanız yerinde bir hareket olur. Odanızdaki gün ışığı, melatonin üretimini durdur ve daha kolay uyanmamızı sağlar.Görünüm: Karbonhidrat kaynaklarımız sabahın erken saatlerine kadar boşalmış oluyor. Kaynaklarınızı bu aralar doldurmazsanız, kısa sürede açlık hissi baş gösterecektir. “Uykuda zayıflamak” adlı kitabın yazarı Dr. Detlef Pape, sabah kahvaltısında marmelatlı ekmek ve meyveli müsli gibi karbonhidrattan oluşan besinler tüketmenizi öneriyor. Geceleri cilt kuruduğu için uyandıktan sonra yüzünüze antioksidan içerikli bir krem sürmek hiç de kötü bir fikir değil! 09.00 – 12.00 : Beden: Bağışıklık sistemi sabah saatlerinde kolayca zarar görebiliyor. Bu yüzden, ince giysilerle sokağa çıkmamak ve çevredeki hasta kişilerle yakın temasta bulunmamak gerek. Ağrıya karşı duyarlılığınız bu saatlerde de hâlâ devam ediyor. Bu yüzden, akupunktur randevunuzu öğleden sonraya ertelemek sizin yararınıza olacaktır. Ancak, aşılarınızı şimdi yaptırmanızda fayda var çünkü vücudunuz aşıyı en iyi ve en az yan etkiyle bu saatlerde kabul ediyor. Artı olarak, güç gerektiren sporları daha geç saatte yapmanız daha faydalı olacaktır. Zihin: Beyindeki maddelerin en aktif olduğu saat aralığı bu saatler. Yapılan araştırmalara göre; insan algısı sabah 10.00’dan itibaren en üst seviyeye ulaşıyor, zihnimiz daha yaratıcı ve daha dinamik oluyor. Bu sebeple, özellikle de analitik yeteneğinizi ortaya koyabileceğiniz görevlerinizi bu saatlerde yapmanız oldukça mantıklı olacaktır! Görünüm: Pankreasın rahatlaması için yemek yedikten bir 3 saat sonrasına kadar yemek yememeniz gerektiği söyleniyor. Yüksek oranda şeker içeren içeceklerden kaçınmalı ve bunun yerine meyvenin kendisini tüketmeyi tercih etmelisiniz. Cilt ve beyin sağlığı için bolca su tüketmeniz gerektiğini unutmamalısınız!12.00 – 14.00 : Beden: Gün ortasında mide en yüksek verimle çalışmaya hazırlanır. Dolayısıyla, mide ve bağırsak sorunlarının oluşmasını önlemek adına öğle yemeği için en ideal saat aralığı öğlen 12.00’dir. Hemen ardından sindirim işlemi için kan mideye yönlenir ve beyin, kalp ve dolaşım sistemi ile çalışmaya başlar. Bunun sonucunda vücut formdan düşer ve eylem gücü azalmaya başlar. Bu nedenle bacaklarınızı yukarıya doğru uzatın ve bilgisayar karşısında uzun süre kaldığınız için yanan gözlerinizi kapatarak bir süre dinlendirin.Zihin: Günün geri kalan kısmında daha iyi çalışabilmeniz için 30 dakikalık bir şekerleme yapmak verimliliğinizi artıracaktır. Yapılan araştırmalar; şekerlemenin ardından kişilerin daha hızlı reaksiyon gösterdiklerini, daha iyi odaklandıklarını ve daha neşeli hissettiklerini ortaya koyuyor.Görünüm: Gündüzleri aktif bir şekilde çalışıyorsanız, karbonhidrat ile proteinin en iyi şekilde işleyebilmesini sağlayabilir ve böylece kilo almaktan kurtulabilirsiniz.14.00 – 18.00 : Beden: Ağrıya karşı duyarlılığın en düşük olduğu saatlere gelmiş bulunuyoruz. Uykularınızı kaçıran bir doktor randevunuz varsa bu saat aralığında rahatça çözüme kavuşturabilirsiniz.Zihin: Gün ortasında yediğiniz yemeğin sindirimi saat 15.00 gibi sona erdiği için oksijen yeniden beyine yöneliyor. Enerji geri geliyor, zihin tam olarak formuna ulaşıyor. Bu yüzden, her 45 dakikada bir 5 dakika veya en geç her 90 dakikada bir 15 dakika ara verin performansınızı en üst seviyeye çıkarabilirsiniz. Çünkü, bu saatlerde daha yaratıcı oluyor ve problemleri de çok daha kolay çözebiliyoruz.Görünüm: Bu saatlerde yapılan sporun iki misli yarar sağladığı söyleniyor. Vücudunuzun yağ yakması için yüzme ve hafif tempo koşu gibi performans gerektiren spor türlerini tercih edin.18.00 – 21.00 : Beden: Akşam dinlenme vaktinde karaciğeriniz, vücudunuzu toksinlerden maksimum düzeyde arındırıyor. Alkol de bu saatlerde yine çok hızlı bir şekilde vücuttan atılabiliyor. Bu saat aralığında yapacağınız banyo da toksinlerden arınmanız için organizmanızı ayrıca destekliyor. Saat 19.00 itibari ile dört saat boyunca alerjenlere karşı oldukça duyarlı bir süreç var. Dolayısıyla saçlarınızı polenlerden arındırmak için daha erken saatlerde yıkayın ve alerjiye yol açabilecek şeylerden de uzak durun. Saman nezlesi, astım ve romatizmaya karşı geliştirilen ilaçların etkisi bu saatlerde epey artıyor. Aynı şey ağrı kesiciler için de geçerli. Mesela, akşam saatlerinde aynı şiddetteki bir ağrıyı dindirmek için sabaha nazaran daha az ağrı kesici almanız yeterli oluyor.Zihin: Dr. Jan-Dirk Fauteck, bu saatlerde yaşanan süreci şöyle özetliyor: “Vücudumuz bu saatlerde yaşamsal önem taşıyan organların aktivitelerini azaltıyor, bunun sonucunda beynimiz daha az meşgul oluyor ve kafamız da boşalıyor. Böylelikle sanatsal ve yaratıcı dürtülerimiz ortaya çıkıyor, uzun süreli hafızamız da daha verimli bir noktaya geliyor.”Görünüm: Bu saatlerde duyularımız oldukça hassaslaşıyor ve biz de bu sayede akşam yemeğinin tadını çıkarabiliyoruz. Ancak Dr. Pape, zayıflamak isteyenlerin sofralarında proteinli besinlere ağırlık vermesi gerektiğini söylüyor. Akşam yemeğinde yağsız et ve sebze ikilisini tüketmekte hiçbir sakınca yok! 21.00 – 24.00 : Beden: Bütün gün hiçbir ağrı hissetmediğiniz bir yeriniz saat 21:00 gibi ağrımaya başlayabilir. Çünkü, ağrıya en duyarlı olunan saatlere girmiş bulunuyorsunuz. Saat 23.00’den itibaren de bağışıklık sisteminiz kendini yenilemek için başlangıç yapıyor. Dolayısıyla, onu sıkıntıya sokan stres, nikotin ve alkol gibi şeylerden kaçınmaya dikkat edin.Zihin: Tam dinlenme saati. Bu saatlerde sadece bedeninizi değil, aynı zamanda beyninizi de dinlendirmelisiniz. Sevdiğiniz bir kitabı okumak, güzel bir film izlemek veya sevdiğiniz bir müzik türünü dinlemek günün gerginliğini üzerinizden atmanızda en önemli yardımcılarınızdan birisi olacak. Bu saat aralığında melatonin üretimi yaklaşık yarım saat içinde 0 değerinden 100’e ulaşacağı için yorgunluk hissi baş gösterir. Melatonin hormonu gündüz ışıklarının iyiden iyiye çekildiği 21:00’den itibaren salgılanmaya başlıyor ve günün ilk ışıklarına dek en yüksek seviyede seyrediyor.Görünüm: Bağırsak gibi sindirim organları, saat 21.00’den itibaren görevlerini sona erdiriyor. Yatağa girmeden bir iki saat önce yemek yemeyi bırakın ve spor yapmayın. Çünkü vücudunuz şimdi kendini yenileyebilmesi için yoğun enerjiye ihtiyaç duyacak. Ciltte bulunan epidermis hücreleri saat 23.00 ile 04.00 arasında, gündüz saatlerine nazaran tam 8 kat daha hızlı bölünerek kendini yeniliyor. Bu süreci cildinize uygun bir gece kremiyle desteklemeniz oldukça mantıklı bir hareket olacaktır.24.00 – 07.00 : Beden: Biz uyurken vücudumuzun kendini yenileme mekanizması en yüksek performansla çalışıyor. Bağışıklık sistemi de buna paralel olarak saat 01.00 gibi savunma hücrelerini üretiyor. Maalesef geceleri aynı zamanda sinirlerimiz de oldukça hassaslaşıyor. Bu nedenle sırt ağrısından yakınıyorsanız, ağrı kesicinizi uyumadan önce almanızda fayda var. Saat 03.00’e doğru kan basıncımız anlamlı bir şekilde düşmeye başlıyor. Bu saatlerde kan şekeri de düştüğü için kolayca uyanabilirsiniz. Tekrar derin bir uykuya dalmak için size bir parça çikolata yemenizi öneriyoruz. Çünkü çikolata içerdiği mutluluk hormonu serotonin sayesinde vücudunuzun rahatlamasını ve gevşemesini sağlıyor. Organizmamız saat 05.00’den itibaren tekrar uyanıyor, hormonlar ve diğer metabolizma maddeleri de hızla kana karışıyor. Aynı zaman da alkol de! Dolayısıyla siz siz olun, alkol aldıktan sonra asla direksiyon başına geçmeyin.Zihin: Saat 24.00’den itibaren düşünme yeteneğimiz oldukça zayıfladığı için sorunlarınızı bu saatte çözmekten kaçının. Uzmanlar, saat 03.00 sıralarında ise gece kuşlarının bile konsantrasyon sorunu yaşamaya başladıklarına dikkat çekiyor. Ancak sabah saat 05.00 sıralarında vücudumuz kendini yine toparlama sürecine giriyor. Artan kan basıncı sayesinde beynimize tekrar daha fazla oksijen ulaşıyor. Böylelikle azalan enerjimiz de geri geliyor.Görünüm: Uyuyan kişi suç işlemez. Bu aynı zamanda bedenimize de zarar veremeyeceğimiz anlamına geliyor. Şimdi, protein ağırlıklı akşam yemeğinizin faydalarından tüm gece boyunca yararlanma zamanı. Yağ yakımı bu saatlerde de devam ediyor. Vücudunuz, hücrelerin kendini yenileyebilmeleri ve kas yapımı için gerekli olan enerjiyi sağlamak adına yağ hücrelerinden karbonhidrat alıyor. Siz de uykunuzda zayıflamış oluyorsunuz.")
        bilgiler.append(bilgi5)

        let bilgi6 = Bilgilendirme(Title: "Stres Yönetimi ve Bilişsel Terapi", Image: UIImage(named: "bilgi6")!, Details: "Stres evde, okulda, iş yerlerinde, metrobüste kısacası hayatın içinde olan her yerde kendini gösterir. Önümüzdeki kitaba odaklanmamıza, iki gün sonraki sınava çalışmamıza ve hatta yataktan kalkmamıza bile engel olur. Gece yatağa uzanıp hayatımızı sorgulamaya başladığımızda birçok şeyin kendi dışımızda geliştiğini fark ederiz.Kimi zaman derdimizi anlatamamaktan, kimi zaman anlatsak da anlaşılamamaktan kaynaklı bir çaresizlik hissederiz. Kendimizle ve insanlarla olan ilişkilerimizde tekrarlanan problemler bir kısırdöngüye girmemize yol açar.Bu noktada stres yönetimi daha huzurlu, sağlıklı ve verimli bir hayat sürebilmemiz için oldukça önemlidir. Bu amaçla uygulanan bilişsel terapi yaklaşımı, yaşadığımız olumsuzluklara karşı bakış açımızı değiştirmemize yardımcı olur. Nasıl düşündüğümüzün nasıl hissettiğimizi belirlediğini savunan bu yaklaşıma biraz daha yakından bakalım.Günlük hayatta karşılaşılan olumsuzluklar üzerine değerlendirmeler yaparak bireylerin baş etme stratejileri geliştirmesine yardımcı olan bir tedavi yöntemidir. Yaşanan problemin ne olduğu, nerede ve ne zaman meydana geldiği, probleme kimin veya neyin sebep olduğu gibi sorulara yanıt arar.Geçmiş deneyimlerden kaynaklanan düşünce yapılarını tespit eder. Olumsuz bir durumla ilgili zihnimizdeki otomatik düşünce kalıplarını yıkmak için alternatif yollar sunar. Geleceğe yönelik olumsuz çıkarımlar yapmak ve bir problemi genellemek gibi işlevsel olmayan düşünce kalıplarını aşmayı sağlayan yöntemler içerir.Yaşadığımız olumsuzluklar karşısında çoğu zaman kalıplaşmış inanç sistemlerimiz devreye girer. Zor bir okul dönemi geçirmemiz ve notlarımızın istediğimiz gibi olmaması sonucunda zaten hayat boyu başarısızlığa mahkum olduğumuz inancına bağlanıp kalabiliriz. Sevdiğimiz biri tarafından reddedilirsek bunu değersiz olduğumuz düşüncesiyle ilişkilendirebiliriz.Bu tür işlevsel olmayan düşünce kalıpları kendimizle ve çevremizle olan ilişkilerimizi kötü etkileyerek stres seviyemizin artmasına neden olur. Bilişsel terapi yaklaşımı, duygu ve düşüncelerimizi fark etmemizi ve yıkıcı düşünce kalıplarının yerine yapıcı olanları koymamızı sağlar.Olumsuz bir durumla karşılaştığımızda sadece kaybettiklerimize odaklanmak yerine, elde edebileceğimiz yeni fırsatları ve durumun avantajlı taraflarını da görmemize yardım eder. Kendi değerimizin dış unsurlar tarafından değil, kendi içimizdeki düşünce yapısı ile şekillendiğini savunur. Böylece farklı bir bakış açısıyla yeniden değerlendirdiğimiz problemlere, daha yapıcı ve çözüm odaklı bir şekilde yaklaşabildiğimizi fark ederiz.Depresyon, stresle ilişkili oldukça önemli bir rahatsızlıktır. Dr. David Burns “İyi Hissetmek” adlı bilişsel terapi kitabında, orta düzey depresyon hastaları üzerinde yaptığı bir çalışmadan bahseder. Bu çalışmada, “İyi Hissetmek” kitabını okuyan depresyon hastalarının %75’inin üç aylık süre sonunda artık depresyon belirtileri göstermediği görülmüştür.Stres, psikolojik ve fiziksel sağlık problemleri yaşamamıza neden olur ve hayat kalitemizi düşürür. Çoğu zaman, karşılaştığımız problemlere geçmiş deneyimlerimizden kaynaklanan inanç kalıplarımız nedeniyle bir çözüm bulmakta zorlanırız. Belli bir düşünceye saplanıp kalmak, karşılaştığımız olumsuzlukları objektif açıdan değerlendirmemize fırsat vermeyebilir. Böyle anlarda zihnimizden geçen bu düşünceleri fark etmek, yeni olumlu bakış açıları geliştirmeye çalışmak ve genellemelerden kaçınmak oldukça önemlidir.Bilişsel terapi, içinde bulunduğumuz duygu durumunu neden ve nasıllarıyla değerlendirerek duruma ve kendimize karşı objektif bir bakış açısı kazandırmaya çalışır.Otomatik düşünce kalıplarının farkına varmamızı ve işlevsel olmayan bu düşünceler ile olumlu ve yapıcı düşünceleri yer değiştirmemize imkan sağlar.Çözüm odaklı bir yaklaşım benimsememize yardım eder.Nasıl düşündüğümüzün nasıl hissettiğimiz üzerinde oldukça önemli bir etkisi olduğunu savunur.Orta düzey depresyon hastaları üzerinde bile büyük oranda iyileştirici etkisi olduğu bilinmektedir.Bu tedavi yaklaşımını hayatımıza uygulayabiliriz. Böylece duygularımızın ve düşüncelerimizin yönetimini daha iyi sağlayarak kendimizle ve çevremizle ilişkilerimizi iyileştirebilir, sağlıklı, huzurlu ve başarılı bir yaşam sürebiliriz.")
        bilgiler.append(bilgi6)

    }
}

extension NedirVC: UITableViewDelegate,UITableViewDataSource{
    
        func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int {
            return bilgiler.count
        }
        
    func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
        let cell = tableView.dequeueReusableCell(withIdentifier: "cell", for: indexPath) as! CustomTableViewCell
        cell.titles.text = bilgiler[indexPath.row].title
        cell.images.image = bilgiler[indexPath.row].image
        return cell
    }
    func tableView(_ tableView: UITableView, didSelectRowAt indexPath: IndexPath) {
        bilgiSec = bilgiler[indexPath.row]
        self.performSegue(withIdentifier: "toNedirDetayVC", sender: nil)
    }
    override func prepare(for segue: UIStoryboardSegue, sender: Any?) {
        if segue.identifier == "toNedirDetayVC"{
            let destinationVC = segue.destination as! NedirDetayVC
            destinationVC.selectedBilgi = bilgiSec
        }
    }
    func tableView(_ tableView: UITableView, heightForRowAt indexPath: IndexPath) -> CGFloat {
        return 140
    }
}
